/**
 * Typed wrappers around the Tauri IPC surface.
 *
 * The frontend NEVER talks to external services directly — it only invokes
 * Rust commands (Tauri Core) and subscribes to Rust-emitted events. This module
 * is the single place where `invoke` is called, so the command contract stays
 * in one spot.
 */
import { invoke } from '@tauri-apps/api/core';

/** Body returned by the Python sidecar's `GET /health`. */
export interface SidecarHealth {
  status: string;
  service: string;
  /** ISO-8601 timestamp generated by the sidecar (UTC). */
  time: string;
}

/** Result of a frontend → Rust → sidecar → frontend round-trip. */
export interface PingResult {
  reachable: boolean;
  http_status: number;
  port: number;
  round_trip_ms: number;
  /** Rust-side timestamp of when the check ran (freshness, UTC ISO-8601). */
  checked_at: string;
  health: SidecarHealth | null;
  error: string | null;
}

// --- US Market view -------------------------------------------------------

export interface SourceMeta {
  source: string;
  last_fetched_at: string | null;
  status: string; // "ok" | "error" | "unavailable" | "never"
  detail: string | null;
}

export interface IndexQuote {
  code: string;
  value: number | null;
  change_pct: number | null;
  ts: string | null;
}

export interface SectorQuote {
  sector: string;
  ret: number | null; // fraction (0.012 = 1.2%)
  rel_strength: number | null; // fraction
  date: string | null;
}

export interface BreadthQuote {
  date: string | null;
  index: string;
  advancers: number | null;
  decliners: number | null;
  new_highs: number | null;
  new_lows: number | null;
  pct_above_200dma: number | null; // fraction
  universe: number | null;
}

export interface MetricPoint {
  value: number;
  date: string;
  series_id: string;
}

export interface RatesSnapshot {
  us2y: MetricPoint | null;
  us10y: MetricPoint | null;
  twos10s: MetricPoint | null;
  hy_oas: MetricPoint | null;
  dxy: MetricPoint | null;
  vix: MetricPoint | null;
}

export interface CotQuote {
  market: string;
  date: string | null;
  noncomm_net: number | null;
  noncomm_net_prev: number | null;
  noncomm_long: number | null;
  noncomm_short: number | null;
}

export interface UsMarket {
  indices: IndexQuote[];
  sectors: SectorQuote[];
  breadth: BreadthQuote | null;
  rates: RatesSnapshot;
  cot: CotQuote[];
  freshness: SourceMeta[];
}

export interface RefreshOutcome {
  source: string;
  status: string;
  rows: number;
  detail: string | null;
}

export interface RefreshSummary {
  outcomes: RefreshOutcome[];
  at: string;
}

// --- Composite (Home) -----------------------------------------------------

export interface CompositeComponent {
  name: string;
  label: string;
  weight: number; // effective (renormalized) weight
  raw_weight: number;
  n: number | null; // normalized [-1,1], sign applied
  contribution: number;
  available: boolean;
  note: string | null;
}

export interface CompositeResult {
  ts: string;
  score: number; // 0-100
  regime_key: string;
  regime_label: string;
  components: CompositeComponent[];
  coverage: number; // fraction of weight available
  notes: string[];
}

/** Compute + read the market-regime composite. */
export function getComposite(): Promise<CompositeResult> {
  return invoke<CompositeResult>('get_composite');
}

/** Read the US Market view payload from Rust (reads from DuckDB). */
export function getUsMarket(): Promise<UsMarket> {
  return invoke<UsMarket>('get_us_market');
}

