// --- Cross-market / Settings / Credentials (Session 5) ---------------------

export interface CrossTransmission {
  driver: string;
  path: string;
  effect_note: string;
}

export interface MetricLabel {
  label: string;
  value: number | null;
}

export interface CrossMarket {
  transmissions: CrossTransmission[];
  metrics: MetricLabel[];
  freshness: SourceMeta[];
}

export interface SettingKV {
  key: string;
  value: string;
}

export interface CredentialStatus {
  source: string;
  configured: boolean;
}

export function getCrossMarket(): Promise<CrossMarket> {
  return invoke<CrossMarket>('get_cross_market');
}

export function getSettings(): Promise<SettingKV[]> {
  return invoke<SettingKV[]>('get_settings');
}

export function setSetting(key: string, value: string): Promise<void> {
  return invoke<void>('set_setting', { key, value });
}

export function setCredential(source: string, token: string): Promise<void> {
  return invoke<void>('set_credential', { source, token });
}

export function getCredentialStatus(): Promise<CredentialStatus[]> {
  return invoke<CredentialStatus[]>('get_credential_status');
}

export interface AiStatus {
  mode: string;
  provider: string; // "local" | "claude" | "rule"
  label: string;
  detail: string | null;
  local_available: boolean;
  local_endpoint: string | null;
  local_model: string | null;
  claude_available: boolean;
}

export function getAiStatus(): Promise<AiStatus> {
  return invoke<AiStatus>('get_ai_status');
}

/** Per-source last-fetched time + status. */
export function getFreshness(): Promise<SourceMeta[]> {
  return invoke<SourceMeta[]>('get_freshness');
}

/** Manually refresh one source, or all US sources when omitted. */
export function refresh(source?: string): Promise<RefreshSummary> {
  return invoke<RefreshSummary>('refresh', { source: source ?? null });
}

/** Status of the local databases owned by Rust. */
export interface DbStatus {
  duckdb_path: string;
  sqlite_path: string;
  duckdb_exists: boolean;
  sqlite_exists: boolean;
  /** Rust-side timestamp of initialization (UTC ISO-8601). */
  initialized_at: string;
}

/**
 * Ping the sidecar through Rust. Runs the full IPC chain:
 * frontend `invoke` → Rust command → sidecar `GET /health` → result.
 */
export function pingSidecar(): Promise<PingResult> {
  return invoke<PingResult>('ping_sidecar');
}

/** Report the paths and existence of the DuckDB / SQLite files. */
export function getDbStatus(): Promise<DbStatus> {
  return invoke<DbStatus>('get_db_status');
}

/** True when running inside the Tauri webview (vs. a plain browser dev server). */
export function isTauri(): boolean {
  return typeof window !== 'undefined' && '__TAURI_INTERNALS__' in window;
}
